import { Typography } from "@mui/material";

const HeaderMenuLogo = () => {

    return (
        <Typography variant="h6" noWrap component="a" href="/Home"
            sx={{
                mr: 2,
                display: { xs: 'none', md: 'flex' },
                fontFamily: 'monospace',
                fontWeight: 700,
                letterSpacing: '.3rem',
                color: 'white',
                textDecoration: 'none',
            }}
        >
        NPTFC
        </Typography>
    )

}

export default HeaderMenuLogo;
